class Solution {
public:
    int minStable(vector<int>& nums, int maxC) {
        int n = nums.size();
        vector<int> cnt(100001, 0);
        for (int x : nums) {
            for (int i = 2; i * i <= x; i++) {
                if (x % i == 0) {
                    cnt[i]++;
                    while (x % i == 0) x /= i;
                }
            }
            if (x > 1) cnt[x]++;
        }
        int res = 0;
        for (int i = 100000; i >= 2; i--) {
            if (cnt[i] > maxC) {
                res = max(res, cnt[i] - maxC);
            }
        }
        return res;
    }
};
